import React, { useState, useEffect } from 'react';
import { 
  Box, 
  Typography, 
  Grid, 
  Button, 
  Divider, 
  Paper, 
  Chip, 
  Avatar,
  LinearProgress,
  IconButton,
  TextField,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Stack,
  Accordion,
  AccordionSummary,
  AccordionDetails,
  List,
  ListItem,
  ListItemAvatar,
  ListItemText,
  CircularProgress
} from '@mui/material';
import { 
  ArrowBack, 
  Share, 
  CalendarMonth, 
  CardGiftcard, 
  Person, 
  LocalOffer, 
  ExpandMore,
  LocalAtm,
  DirectionsCar,
  Favorite,
  FavoriteBorder,
  ArrowDropDown,
  ArrowDropUp
} from '@mui/icons-material';
import { styled, alpha, useTheme } from '@mui/material/styles';
import { useNavigate, useParams } from 'react-router-dom';
import { motion } from 'framer-motion';
import CarSpecifications, { FeatureType, asFeatureCategory } from '../components/CarSpecifications';
import CarSpecificationsSimple from '../components/CarSpecificationsSimple';
import CarSpecificationsIcons from '../components/CarSpecificationsIcons';
import ImageCarousel from '../components/ImageCarousel';
import CarSpecificationsModal from '../components/CarSpecificationsModal';
import { getRaffle } from '../firebase/services';
import { Raffle as RaffleType } from '../types';

const ImageContainer = styled(Box)(({ theme }) => ({
  width: '100%',
  height: 280,
  borderRadius: theme.spacing(3),
  overflow: 'hidden',
  boxShadow: '0 10px 30px rgba(0,0,0,0.15)',
  position: 'relative',
  [theme.breakpoints.down('sm')]: {
    height: 200,
  },
}));

const DetailCard = styled(Paper)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(3),
  boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
  marginBottom: theme.spacing(3),
}));

const PriceChip = styled(Chip)(({ theme }) => ({
  background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
  color: theme.palette.common.white,
  fontWeight: 700,
  padding: theme.spacing(1, 0.5),
  fontSize: '1.2rem',
  height: 'auto',
}));

const ProgressLabel = styled(Box)(({ theme }) => ({
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  width: '100%',
  marginTop: theme.spacing(1),
}));

const StatsItem = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  marginBottom: theme.spacing(2),
  '& svg': {
    marginRight: theme.spacing(1.5),
    color: theme.palette.primary.main,
  }
}));

const BuyButton = styled(Button)(({ theme }) => ({
  borderRadius: 100,
  padding: theme.spacing(1.5, 4),
  fontSize: '1rem',
  fontWeight: 700,
  background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
  boxShadow: '0 4px 15px rgba(33, 150, 243, 0.35)',
  transition: 'all 0.3s ease',
  '&:hover': {
    boxShadow: '0 6px 20px rgba(33, 150, 243, 0.5)',
    transform: 'translateY(-2px)',
  }
}));

const StatsContainer = styled(Box)(({ theme }) => ({
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: theme.spacing(2),
}));

const StatsBox = styled(Box)(({ theme }) => ({
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
}));

interface Participant {
  id: string;
  name: string;
  avatar: string;
  tickets: number;
  time: string;
}

interface Winner {
  id: string;
  name: string;
  avatar: string;
  car: string;
  date: string;
}

interface ExtendedRaffle extends RaffleType {
  recentParticipants: Participant[];
  winners: Winner[];
}

// Default empty raffle data for loading state
const emptyRaffleData: Partial<ExtendedRaffle> = {
  id: '',
  title: '',
  images: [],
  description: '',
  ticketsSold: 0,
  totalTickets: 0,
  price: 0,
  year: 0,
  color: '',
  participants: 0,
  endDate: null,
  engine: '',
  power: '',
  acceleration: '',
  maxSpeed: '',
  features: [],
  carSpecifications: null,
  companyId: '',
  status: 'active' as const,
  startDate: null,
  createdAt: null,
  recentParticipants: [],
  winners: []
};

const RaffleDetailPage: React.FC = () => {
  const theme = useTheme();
  const navigate = useNavigate();
  const { id } = useParams();
  const [ticketCount, setTicketCount] = useState(1);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [isFavorite, setIsFavorite] = useState(false);
  const [specsModalOpen, setSpecsModalOpen] = useState(false);
  const [raffleData, setRaffleData] = useState<Partial<ExtendedRaffle>>(emptyRaffleData);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  
  useEffect(() => {
    const fetchRaffleData = async () => {
      if (!id) return;
      
      try {
        setLoading(true);
        const data = await getRaffle(id);
        
        if (data) {
          // Add mock data for recent participants and winners until we implement that feature
          const mockRecentParticipants: Participant[] = [
            { id: '1', name: 'Алексей К.', avatar: 'https://randomuser.me/api/portraits/men/32.jpg', tickets: 3, time: '12 минут назад' },
            { id: '2', name: 'Мария В.', avatar: 'https://randomuser.me/api/portraits/women/44.jpg', tickets: 1, time: '27 минут назад' },
            { id: '3', name: 'Дмитрий П.', avatar: 'https://randomuser.me/api/portraits/men/67.jpg', tickets: 5, time: '49 минут назад' },
            { id: '4', name: 'Елена С.', avatar: 'https://randomuser.me/api/portraits/women/22.jpg', tickets: 2, time: '1 час назад' },
          ];
          
          const mockWinners: Winner[] = [
            { id: '5', name: 'Сергей И.', avatar: 'https://randomuser.me/api/portraits/men/15.jpg', car: 'Audi Q7', date: '05.11.2023' },
            { id: '6', name: 'Анна М.', avatar: 'https://randomuser.me/api/portraits/women/3.jpg', car: 'Mercedes GLE', date: '15.10.2023' },
          ];
          
          // Format the endDate if it's a Timestamp
          let formattedEndDate = '';
          if (data.endDate) {
            try {
              // Try to convert Firebase Timestamp to formatted date
              if (typeof data.endDate.toDate === 'function') {
                const date = data.endDate.toDate();
                formattedEndDate = new Intl.DateTimeFormat('ru-RU', {
                  day: '2-digit',
                  month: '2-digit',
                  year: 'numeric'
                }).format(date);
              } else {
                formattedEndDate = String(data.endDate);
              }
            } catch (e) {
              formattedEndDate = String(data.endDate);
            }
          }
          
          setRaffleData({
            ...data,
            endDate: formattedEndDate || null,
            recentParticipants: mockRecentParticipants,
            winners: mockWinners
          });
        } else {
          setError('Розыгрыш не найден');
        }
      } catch (err) {
        console.error('Ошибка при загрузке данных розыгрыша:', err);
        setError('Не удалось загрузить данные розыгрыша');
      } finally {
        setLoading(false);
      }
    };
    
    fetchRaffleData();
  }, [id]);
  
  const progress = raffleData.ticketsSold && raffleData.totalTickets 
    ? (raffleData.ticketsSold / raffleData.totalTickets) * 100 
    : 0;
    
  const totalPrice = (raffleData.price || 0) * ticketCount;
  
  const handleIncrease = () => {
    setTicketCount(prev => prev + 1);
  };
  
  const handleDecrease = () => {
    if (ticketCount > 1) {
      setTicketCount(prev => prev - 1);
    }
  };
  
  const handleBuyClick = () => {
    setDialogOpen(true);
  };
  
  const handleCloseDialog = () => {
    setDialogOpen(false);
  };
  
  const handleFavoriteToggle = () => {
    setIsFavorite(!isFavorite);
  };
  
  const handleOpenSpecsModal = () => {
    setSpecsModalOpen(true);
  };
  
  const handleCloseSpecsModal = () => {
    setSpecsModalOpen(false);
  };
  
  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '50vh' }}>
        <CircularProgress />
      </Box>
    );
  }
  
  if (error) {
    return (
      <Box sx={{ padding: 2, textAlign: 'center' }}>
        <Typography variant="h6" color="error">{error}</Typography>
        <Button 
          variant="outlined" 
          onClick={() => navigate(-1)} 
          sx={{ mt: 2 }}
          startIcon={<ArrowBack />}
        >
          Вернуться назад
        </Button>
      </Box>
    );
  }
  
  return (
    <Box sx={{ padding: 2, paddingBottom: 10 }}>
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4 }}
      >
        <Box sx={{ mb: 3, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Button
            startIcon={<ArrowBack />}
            onClick={() => navigate(-1)}
            sx={{ fontWeight: 600, color: 'text.secondary' }}
          >
            Назад
          </Button>
          
          <Box>
            <IconButton 
              aria-label="добавить в избранное" 
              sx={{ mr: 1 }}
              onClick={handleFavoriteToggle}
            >
              {isFavorite ? <Favorite color="error" /> : <FavoriteBorder />}
            </IconButton>
            <IconButton aria-label="поделиться">
              <Share />
            </IconButton>
          </Box>
        </Box>
        
        <ImageCarousel 
          images={raffleData.images || [raffleData.image]} 
          height={280} 
          autoPlay={true}
          interval={5000}
        />
        
        <DetailCard sx={{ mt: 3 }}>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', mb: 2 }}>
            <Typography variant="h5" component="h1" sx={{ fontWeight: 700 }}>
              {raffleData.title}
            </Typography>
            <PriceChip label={`${raffleData.price} ₽`} />
          </Box>
          
          <Divider sx={{ my: 2 }} />
          
          <Box sx={{ mb: 3 }}>
            <Typography variant="body1" sx={{ mb: 2, color: 'text.secondary', lineHeight: 1.6 }}>
              {raffleData.description}
            </Typography>
            
            <StatsContainer>
              <StatsBox>
                <Typography variant="body2" color="text.secondary">Участников</Typography>
                <Typography variant="h6" sx={{ fontWeight: 600 }}>{raffleData.participants || 0}</Typography>
              </StatsBox>
              <StatsBox>
                <Typography variant="body2" color="text.secondary">Продано билетов</Typography>
                <Typography variant="h6" sx={{ fontWeight: 600 }}>{raffleData.ticketsSold}</Typography>
              </StatsBox>
              <StatsBox>
                <Typography variant="body2" color="text.secondary">Всего билетов</Typography>
                <Typography variant="h6" sx={{ fontWeight: 600 }}>{raffleData.totalTickets}</Typography>
              </StatsBox>
            </StatsContainer>
            
            <Box sx={{ mb: 2 }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                <Typography variant="body2" color="text.secondary">
                  Продано билетов
                </Typography>
                <Typography variant="body2" fontWeight={600}>
                  {raffleData.ticketsSold} из {raffleData.totalTickets}
                </Typography>
              </Box>
              <LinearProgress 
                variant="determinate" 
                value={progress} 
                sx={{
                  height: 8,
                  borderRadius: 4,
                  backgroundColor: alpha(theme.palette.primary.main, 0.1),
                  '& .MuiLinearProgress-bar': {
                    borderRadius: 4,
                    background: `linear-gradient(90deg, ${theme.palette.primary.main} 0%, ${theme.palette.primary.dark} 100%)`,
                  }
                }}
              />
            </Box>
            
            <Box sx={{ display: 'flex', justifyContent: 'center', mt: 4 }}>
              <BuyButton 
                variant="contained" 
                size="large" 
                fullWidth
                onClick={handleBuyClick}
              >
                Купить билет
              </BuyButton>
            </Box>
          </Box>
        </DetailCard>
        
        <Box sx={{ mb: 3 }}>
          <CarSpecificationsIcons 
            engine={raffleData.engine}
            power={raffleData.power}
            acceleration={raffleData.acceleration}
            maxSpeed={raffleData.maxSpeed}
            color={raffleData.color}
            year={raffleData.year}
            carSpecifications={raffleData.carSpecifications}
          />
          
          <Box sx={{ mt: 3 }}>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
              <Typography variant="h6" fontWeight={600}>
                Характеристики автомобиля
              </Typography>
              <Button 
                variant="outlined" 
                size="small" 
                onClick={handleOpenSpecsModal}
                endIcon={<ExpandMore />}
              >
                Подробнее
              </Button>
            </Box>
            
            <CarSpecifications 
              engine={raffleData.engine}
              power={raffleData.power}
              acceleration={raffleData.acceleration}
              maxSpeed={raffleData.maxSpeed}
              color={raffleData.color}
              year={raffleData.year}
              features={raffleData.features}
              carSpecifications={raffleData.carSpecifications}
            />
          </Box>
          
          <Accordion sx={{ borderRadius: 3, mb: 2, overflow: 'hidden', boxShadow: '0 4px 20px rgba(0,0,0,0.08)', mt: 2 }}>
            <AccordionSummary
              expandIcon={<ExpandMore />}
              aria-controls="participants-content"
              id="participants-header"
            >
              <Typography variant="h6" sx={{ fontWeight: 600 }}>
                Недавние участники
              </Typography>
            </AccordionSummary>
            <AccordionDetails>
              <List sx={{ width: '100%', bgcolor: 'background.paper' }}>
                {raffleData.recentParticipants.map((participant) => (
                  <ListItem key={participant.id} alignItems="flex-start" sx={{ px: 0 }}>
                    <ListItemAvatar>
                      <Avatar alt={participant.name} src={participant.avatar} />
                    </ListItemAvatar>
                    <ListItemText
                      primary={
                        <Typography variant="subtitle1" fontWeight={500}>
                          {participant.name}
                        </Typography>
                      }
                      secondary={
                        <React.Fragment>
                          <Typography
                            component="span"
                            variant="body2"
                            color="text.primary"
                          >
                            Купил(а) {participant.tickets} {
                              participant.tickets === 1 ? 'билет' : 
                              participant.tickets < 5 ? 'билета' : 'билетов'
                            }
                          </Typography>
                          {` — ${participant.time}`}
                        </React.Fragment>
                      }
                    />
                  </ListItem>
                ))}
              </List>
            </AccordionDetails>
          </Accordion>
          
          <Accordion sx={{ borderRadius: 3, overflow: 'hidden', boxShadow: '0 4px 20px rgba(0,0,0,0.08)' }}>
            <AccordionSummary
              expandIcon={<ExpandMore />}
              aria-controls="winners-content"
              id="winners-header"
            >
              <Typography variant="h6" sx={{ fontWeight: 600 }}>
                Недавние победители
              </Typography>
            </AccordionSummary>
            <AccordionDetails>
              <List sx={{ width: '100%', bgcolor: 'background.paper' }}>
                {raffleData.winners.map((winner) => (
                  <ListItem key={winner.id} alignItems="flex-start" sx={{ px: 0 }}>
                    <ListItemAvatar>
                      <Avatar alt={winner.name} src={winner.avatar} />
                    </ListItemAvatar>
                    <ListItemText
                      primary={
                        <Typography variant="subtitle1" fontWeight={500}>
                          {winner.name}
                        </Typography>
                      }
                      secondary={
                        <React.Fragment>
                          <Typography
                            component="span"
                            variant="body2"
                            color="text.primary"
                          >
                            Выиграл(а) {winner.car}
                          </Typography>
                          {` — ${winner.date}`}
                        </React.Fragment>
                      }
                    />
                  </ListItem>
                ))}
              </List>
            </AccordionDetails>
          </Accordion>
        </Box>
      </motion.div>
      
      {/* Модальное окно с подробными характеристиками */}
      <CarSpecificationsModal 
        open={specsModalOpen}
        onClose={handleCloseSpecsModal}
        carSpecs={raffleData.carSpecifications}
        features={raffleData.features}
      />
      
      {/* Диалог покупки билета */}
      <Dialog
        open={dialogOpen}
        onClose={handleCloseDialog}
        PaperProps={{
          sx: {
            borderRadius: 3,
            maxWidth: 'sm',
            width: '100%',
          },
        }}
      >
        <DialogTitle sx={{ pb: 1 }}>
          <Typography variant="h6" component="div" sx={{ fontWeight: 600 }}>
            Покупка билета
          </Typography>
        </DialogTitle>
        
        <DialogContent dividers>
          <Typography variant="body1" sx={{ mb: 2 }}>
            Вы покупаете {ticketCount} {
              ticketCount === 1 ? 'билет' : 
              ticketCount < 5 ? 'билета' : 'билетов'
            } на розыгрыш автомобиля:
          </Typography>
          
          <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
            <Box
              component="img"
              sx={{
                width: 80,
                height: 80,
                objectFit: 'cover',
                borderRadius: 2,
                mr: 2,
              }}
              src={raffleData.images[0]}
              alt={raffleData.title}
            />
            <Box>
              <Typography variant="subtitle1" sx={{ fontWeight: 600 }}>
                {raffleData.title}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Розыгрыш состоится: {raffleData.endDate}
              </Typography>
            </Box>
          </Box>
          
          <Box sx={{ bgcolor: alpha(theme.palette.primary.main, 0.05), p: 2, borderRadius: 2, mb: 3 }}>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
              <Typography variant="body1">
                Стоимость билета:
              </Typography>
              <Typography variant="body1">
                {raffleData.price} ₽
              </Typography>
            </Box>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
              <Typography variant="body1">
                Количество:
              </Typography>
              <Typography variant="body1">
                {ticketCount} шт.
              </Typography>
            </Box>
            <Divider sx={{ my: 1 }} />
            <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
              <Typography variant="subtitle1" sx={{ fontWeight: 600 }}>
                Итого к оплате:
              </Typography>
              <Typography variant="subtitle1" sx={{ fontWeight: 700, color: 'primary.main' }}>
                {totalPrice} ₽
              </Typography>
            </Box>
          </Box>
          
          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
            После оплаты вы получите уведомление с номером вашего билета. Розыгрыш будет проведен в прямом эфире {raffleData.endDate}.
          </Typography>
        </DialogContent>
        
        <DialogActions sx={{ p: 2 }}>
          <Button onClick={handleCloseDialog} color="inherit">
            Отмена
          </Button>
          <Button variant="contained" color="primary">
            Оплатить {totalPrice} ₽
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default RaffleDetailPage;
